@app.route('/query/profiles', methods=['POST']) 
def query():
    #Get data sent by client side (JSON). Convert to dict for querying. 
    userInput = json.loads(request.data) 
    name = userInput['name'] 
    age = int(userInput['age']) 

    #Check for input errors and return message back to the client side (JSON), status 403 
    if name is None:
        return json.dumps({"message" : "No name specified"}), 403
    elif age < 18 or age > 95: 
        return json.dumps({"message": "Age must be between 18 and 95"}), 403

    #Query the collection of user profile and return results 
    col_userProfile.find({'age' : {'$lte': int(userInput['age']), '$gte': int(userInput['age'])}, 'name' : name })
    return json.dumps(col_userProfile) 

